registerFunction('checkPattern', function(state, cards) {
  var n = cards.length;
  if (n === 0) return null;
  if (n === 2) {
    var ranks = cards.map(function(c) { return c.rank; });
    if (ranks.indexOf('small_joker') >= 0 && ranks.indexOf('big_joker') >= 0) {
      return { type: 'rocket', mainValue: 18 };
    }
  }
  var counts = new Map();
  for (var i = 0; i < cards.length; i++) {
    var v = cards[i].value;
    counts.set(v, (counts.get(v) || 0) + 1);
  }
  var values = Array.from(counts.keys()).sort(function(a, b) { return a - b; });
  var countVals = Array.from(counts.values());
  if (n === 4 && counts.size === 1) return { type: 'bomb', mainValue: values[0] };
  if (n === 1) return { type: 'single', mainValue: values[0] };
  if (n === 2 && counts.size === 1) return { type: 'pair', mainValue: values[0] };
  if (n === 3 && counts.size === 1) return { type: 'triple', mainValue: values[0] };
  if (n === 4 && countVals.indexOf(3) >= 0 && countVals.indexOf(1) >= 0) {
    var tv = values.find(function(v) { return counts.get(v) === 3; });
    return { type: 'triple_single', mainValue: tv };
  }
  if (n === 5 && countVals.indexOf(3) >= 0 && countVals.indexOf(2) >= 0) {
    var tv2 = values.find(function(v) { return counts.get(v) === 3; });
    return { type: 'triple_pair', mainValue: tv2 };
  }
  if (n >= 5 && countVals.every(function(c) { return c === 1; })) {
    var straight = true;
    for (var j = 1; j < values.length; j++) { if (values[j] !== values[j-1] + 1) { straight = false; break; } }
    if (straight && values[values.length-1] < 15) return { type: 'straight', mainValue: values[values.length-1], length: n };
  }
  if (n >= 6 && n % 2 === 0 && countVals.every(function(c) { return c === 2; })) {
    var sp = true;
    for (var k = 1; k < values.length; k++) { if (values[k] !== values[k-1] + 1) { sp = false; break; } }
    if (sp && values[values.length-1] < 15) return { type: 'straight_pair', mainValue: values[values.length-1], length: n/2 };
  }
  return null;
});

registerFunction('comparePatterns', function(state, a, b) {
  if (a.type === 'rocket') return 1;
  if (b.type === 'rocket') return -1;
  if (a.type === 'bomb' && b.type !== 'bomb') return 1;
  if (b.type === 'bomb' && a.type !== 'bomb') return -1;
  if (a.type === b.type && a.length === b.length) return a.mainValue - b.mainValue;
  return 0;
});
